import Hero from "@/components/Hero";
import VideoRow from "@/components/VideoRow";
import { categories, getFeaturedVideo, getVideosByCategory } from "@/data/videos";

export default function Home() {
  const featured = getFeaturedVideo();

  return (
    <div>
      <Hero video={featured} />

      <div id="categories" className="-mt-16 relative z-10 space-y-2 pb-12">
        {categories.map((category) => (
          <VideoRow
            key={category.slug}
            title={category.title}
            categorySlug={category.slug}
            videos={getVideosByCategory(category.slug)}
          />
        ))}
      </div>
    </div>
  );
}
